inline constexpr std::size_t kNonHeroEntityCount = 610;

/// Linear lookup by id. (50–100 entries, O(N) is fine).
inline const EntityInfo* FindNonHeroEntity(uint32_t id) noexcept {
    for (const auto& e : kNonHeroEntities) {
        if (e.id == id) return &e;
    }
    return nullptr;
}

inline const char* NonHeroEntityName(uint32_t id) noexcept {
    const auto* e = FindNonHeroEntity(id);
    return e ? e->name_zhCN : nullptr;
}

inline bool IsNonHeroEntity(uint32_t id) noexcept { return FindNonHeroEntity(id) != nullptr; }

inline bool IsTurretEntity(uint32_t id) noexcept {
    const auto* e = FindNonHeroEntity(id); return e && e->type == EntityType::Turret;
}
inline bool IsProjectileEntity(uint32_t id) noexcept {
    const auto* e = FindNonHeroEntity(id); return e && e->type == EntityType::Projectile;
}
inline bool IsSummonEntity(uint32_t id) noexcept {
    const auto* e = FindNonHeroEntity(id); return e && e->type == EntityType::Summon;
}
inline bool IsBotEntity(uint32_t id) noexcept {
    const auto* e = FindNonHeroEntity(id); return e && e->type == EntityType::Bot;
}

/// Iterate all entities spawned by this hero. Caller supplies a functor.
template <typename F> inline void ForEachEntityOfHero(uint32_t hero_id, F&& fn) noexcept {
    for (const auto& e : kNonHeroEntities) if (e.owner_hero_id == hero_id) fn(e);
}

/// Find the first entity spawned by this hero on a given keybind slot.
/// e.g. FindEntityBySlot(0x2, "Ult") → "死亡绽放" spawn (if any).
inline const EntityInfo* FindEntityBySlot(uint32_t hero_id, const char* slot) noexcept {
    if (!slot) return nullptr;
    for (const auto& e : kNonHeroEntities) {
        if (e.owner_hero_id != hero_id) continue;
        if (e.slot[0] != slot[0]) continue;   // fast first-char reject
        // exact match (ASCII-safe)
        const char* a = e.slot; const char* b = slot;
        while (*a && *a == *b) { ++a; ++b; }
        if (*a == 0 && *b == 0) return &e;
    }
    return nullptr;
}

/// Quick counters for a hero: number of entity bindings per slot.
inline std::size_t CountHeroEntities(uint32_t hero_id) noexcept {
    std::size_t n = 0;
    for (const auto& e : kNonHeroEntities) if (e.owner_hero_id == hero_id) ++n;
    return n;
}

inline const char* EntityTypeName(EntityType t) noexcept {
    switch (t) {
    case EntityType::Turret: return "Turret";
    case EntityType::Projectile: return "Projectile";
    case EntityType::Summon: return "Summon";
    case EntityType::Bot: return "Bot";
    case EntityType::Decoy: return "Decoy";
    case EntityType::Other: return "Other";
    }
    return "?";
}

inline const EntityInfo* NonHeroEntitiesBegin() noexcept { return kNonHeroEntities; }
inline const EntityInfo* NonHeroEntitiesEnd()   noexcept { return kNonHeroEntities + kNonHeroEntityCount; }

/// AnyEntityName is retained for compat. Now just wraps FindNonHeroEntity.
inline const char* AnyEntityName(uint32_t id) noexcept {
    if (const auto* e = FindNonHeroEntity(id)) return e->name_zhCN;
    return nullptr;
}

